90	function formatTime(dateStr) {
91	  if (!dateStr) return "--:--:--";
92	  try {
93	    const d = new Date(dateStr);
94	    if (isNaN(d.getTime())) return "--:--:--";
95	    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
96	  } catch {
97	    return "--:--:--";
98	  }
99	}
