101	function formatDate(dateStr) {
102	  if (!dateStr) return "";
103	  try {
104	    const d = new Date(dateStr);
105	    if (isNaN(d.getTime())) return "";
106	    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
107	  } catch {
108	    return "";
109	  }
110	}
