112	function timeAgo(dateStr) {
113	  if (!dateStr) return "";
114	  try {
115	    const d = new Date(dateStr);
116	    const now = new Date();
117	    const diff = now - d;
118	    if (diff < 0) return "just now";
119	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
120	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
121	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
122	    return `${Math.floor(diff / 86400000)}d ago`;
123	  } catch {
124	    return "";
125	  }
126	}
127	
128	function isNew(dateStr) {
129	  if (!dateStr) return false;
130	  try {
131	    const d = new Date(dateStr);
132	    return (Date.now() - d.getTime()) < NEW_THRESHOLD_MS;
133	  } catch {
134	    return false;
135	  }
136	}
