153	async function fetchNews() {
154	  try {
155	    const params = new URLSearchParams({ limit: DEFAULT_LIMIT });
156	    if (state.filter.dateFrom) params.set("from", state.filter.dateFrom);
157	    if (state.filter.dateTo) params.set("to", state.filter.dateTo);
158	    const res = await SignalAuth.fetch(`${API}/news?${params}`);
159	    if (!res.ok) throw new Error(`HTTP ${res.status}`);
160	    const data = await res.json();
161	    state.connected = true;
162	    state.loading = false;
163	    state.fetchCount++;
164	    state.lastRefresh = new Date().toISOString();
165	
166	    if (data.items && data.items.length > 0) {
167	      // Detect new items
168	      const newIds = new Set();
169	      for (const item of data.items) {
170	        if (!state.seenIds.has(item.id)) {
171	          newIds.add(item.id);
172	          state.seenIds.add(item.id);
173	        }
174	      }
175	
176	      // Play sound for new items if enabled
177	      if (state.soundEnabled && newIds.size > 0 && state.fetchCount > 1) {
178	        playNotificationSound();
179	      }
180	
181	      state.newIds = newIds;
182	      state.items = data.items;
183	      state.totalFetched = data.count;
184	
185	      // Calculate items/second
186	      const elapsed = (Date.now() - state.startTime) / 1000;
187	      state.itemsPerSecond = elapsed > 0 ? (state.totalFetched / elapsed).toFixed(1) : 0;
188	    }
189	
190	    renderNews();
191	    updateStatusBar();
192	    updateConnectionStatus(true);
193	  } catch (err) {
194	    state.connected = false;
195	    state.loading = false;
196	    updateConnectionStatus(false);
197	    if (state.items.length === 0) {
198	      renderEmpty("Unable to connect to API. Retrying...");
199	    }
200	  }

