444	function bindColumnResizeHandles() {
445	  const handles = document.querySelectorAll('.col-resize-handle');
446	  handles.forEach(handle => {
447	    handle.addEventListener('mousedown', onResizeStart);
448	    handle.addEventListener('dblclick', onResizeAutoFit);
449	  });
