452	function onResizeStart(e) {
453	  e.preventDefault();
454	  e.stopPropagation();
455	  const handle = e.target;
456	  const th = handle.parentElement;
457	  const colId = handle.dataset.colId;
458	  const startX = e.clientX;
459	  const startWidth = th.offsetWidth;
460	
461	  const table = document.querySelector('.news-table');
462	  if (table) table.style.tableLayout = 'fixed';
463	
464	  document.body.style.cursor = 'col-resize';
465	  document.body.style.userSelect = 'none';
466	  handle.classList.add('active');
467	
468	  function onMouseMove(ev) {
469	    const delta = ev.clientX - startX;
470	    const newWidth = Math.max(MIN_COL_WIDTH, startWidth + delta);
471	    th.style.width = newWidth + 'px';
472	  }
473	
474	  function onMouseUp(ev) {
475	    document.removeEventListener('mousemove', onMouseMove);
476	    document.removeEventListener('mouseup', onMouseUp);
477	    document.body.style.cursor = '';
478	    document.body.style.userSelect = '';
479	    handle.classList.remove('active');
480	
481	    const delta = ev.clientX - startX;
482	    const finalWidth = Math.max(MIN_COL_WIDTH, startWidth + delta);
483	    state.columnWidths[colId] = finalWidth;
484	    saveColumnWidths();
485	    renderTableHeader();
486	    renderNews();
487	  }
488	
489	  document.addEventListener('mousemove', onMouseMove);
490	  document.addEventListener('mouseup', onMouseUp);
491	}
