493	function onResizeAutoFit(e) {
494	  e.preventDefault();
495	  e.stopPropagation();
496	  const colId = e.target.dataset.colId;
497	  const cols = getVisibleColumns();
498	  const colIndex = cols.findIndex(c => c.id === colId);
499	  if (colIndex === -1) return;
500	
501	  const rows = document.querySelectorAll('#news-body tr');
502	  let maxWidth = MIN_COL_WIDTH;
503	
504	  // Measure header text width
505	  const th = e.target.parentElement;
506	  const headerSpan = document.createElement('span');
507	  headerSpan.style.cssText = 'visibility:hidden;position:absolute;white-space:nowrap;font-size:10px;font-weight:600;letter-spacing:0.06em;text-transform:uppercase;';
508	  headerSpan.textContent = th.textContent;
509	  document.body.appendChild(headerSpan);
510	  maxWidth = Math.max(maxWidth, headerSpan.offsetWidth + 32); // 24px padding + 8px handle
511	  document.body.removeChild(headerSpan);
512	
513	  // Measure cell content widths
514	  rows.forEach(row => {
515	    if (row.classList.contains('skeleton-row')) return;
516	    const cells = row.querySelectorAll('td');
517	    const cell = cells[colIndex];
518	    if (!cell) return;
519	    const measurer = document.createElement('div');
520	    measurer.style.cssText = 'visibility:hidden;position:absolute;white-space:nowrap;font-size:12px;';
521	    measurer.innerHTML = cell.innerHTML;
522	    document.body.appendChild(measurer);
523	    maxWidth = Math.max(maxWidth, measurer.offsetWidth + 24); // 24px padding
524	    document.body.removeChild(measurer);
525	  });
526	
527	  // Cap at reasonable max
528	  maxWidth = Math.min(maxWidth, 600);
529	
530	  const table = document.querySelector('.news-table');
531	  if (table) table.style.tableLayout = 'fixed';
532	
533	  state.columnWidths[colId] = maxWidth;
534	  saveColumnWidths();
535	  renderTableHeader();
536	  renderNews();
537	}
