642	
643	      const rect = item.getBoundingClientRect();
644	      const midY = rect.top + rect.height / 2;
645	      if (e.clientY < midY) {
646	        item.classList.add('drag-over-above');
647	      } else {
648	        item.classList.add('drag-over-below');
649	      }
