663	      const rect = item.getBoundingClientRect();
664	      const midY = rect.top + rect.height / 2;
665	      if (e.clientY < midY) {
666	        list.insertBefore(dragSrcEl, item);
667	      } else {
668	        list.insertBefore(dragSrcEl, item.nextSibling);
669	      }
670	
671	      // Update column order from DOM order
